remarks.example:
This is a code example:


TrackingDatabase database = this.recordStorageHandler.GetDatabase("StrucA", this.sessionContext);
foreach (var highProximity in database.higherProximityStructures)
{
    var structureName = highProximity.Structure.GetStructureName();
    Prime.Base.ServiceStore<IConsoleService>.Service.PrintDebug(() => $"Name of higher proximity structure = {structureName}.", this.sessionContext);
if (highProximity.Structure.HasBeenInitialized())
    {
        Prime.Base.ServiceStore<IConsoleService>.Service.PrintDebug(() => $"Structure {highProximity.Structure.StructureName} has been initialized.", this.sessionContext);
    }
}

This is a code example:


TrackingDatabase database = this.recordStorageHandler.GetDatabase("StrucA", this.sessionContext);
foreach (var highProximity in database.higherProximityStructures)
{
    var elementNames = new List<string>(highProximity.ElementMap.Keys);
    highProximity.Structure.InitializeElementValues(elementNames);
}

