var trackingStructureHandler = Prime.Base.ServiceStore<IDefeatureTrackingService>.Service.CreateTrackingStructureHandler("Struct0", this.SessionContext);
var ruleEvaluationStatus = trackingStructureHandler.EvaluateRule(new BitArray(4, true), this.SessionContext);
if (ruleEvaluationStatus)
{
    Prime.Base.ServiceStore.<IConsoleService>.Service.PrintDebug(() => "Value passed rule check", this.SessionContext);
}
else
{
    Prime.Base.ServiceStore.<IConsoleService>.Service.PrintDebug(() => "Value failed rule check", this.SessionContext);
}

